#include <stdio.h>
#include <string.h>

// Define the block structure
struct Block {
 char previousHash[64];
 char timestamp[32];
 char nonce[32];
 char merkleRoot[64];
 char transactions[1024];
};

int main() {
 // Create a new block
 struct Block block;

 // Initialize the block fields
 strcpy(block.previousHash, 'previousHash');
 strcpy(block.timestamp, 'timestamp');
 strcpy(block.nonce, 'nonce');
 strcpy(block.merkleRoot, 'merkleRoot');
 strcpy(block.transactions, 'transactions');

 // Print the block structure
 printf('Block structure:\n');
 printf('Previous hash: %s\n', block.previousHash);
 printf('Timestamp: %s\n', block.timestamp);
 printf('Nonce: %s\n', block.nonce);
 printf('Merkle root: %s\n', block.merkleRoot);
 printf('Transactions: %s\n', block.transactions);

 return 0;
}
